+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const paths = options.searchPaths ?? [Deno.cwd()];
+  const formats = options.formats ?? [".json", ".rc"];
+  let result: Record<string, unknown> = {};
+  let configPath: string | undefined;
+
+  for (const searchPath of paths) {
+    const file = await findConfig(searchPath, options.name, formats);
+    if (!file) continue;
+
+    const content = await Deno.readTextFile(file);
+    const values = parseConfig(content, file, options.parser);
+    // Earlier paths take precedence when merging.
+    result = options.mergeConfigs ? { ...values, ...result } : values;
+    configPath ??= file;
+    if (!options.mergeConfigs) break;
+  }
+
+  return { path: configPath, values: flattenConfig(result) };
+}
+
+async function findConfig(
+  searchPath: string,
+  name: string,
+  formats: string[],
+): Promise<string | undefined> {
+  for (const format of formats) {
+    const filename = format === ".rc" ? `.${name}rc` : `${name}${format}`;
+    const path = `${searchPath.replace(/[\\\\/]$/, "")}/${filename}`;
+    try {
+      if ((await Deno.stat(path)).isFile) return path;
+    } catch (error) {
+      if (!(error instanceof Deno.errors.NotFound)) throw error;
+    }
+  }
+}
+
+function parseConfig(
+  content: string,
+  path: string,
+  parser?: (content: string) => Record<string, unknown>,
+): Record<string, unknown> {
+  try {
+    const value = parser ? parser(content) : path.endsWith(".rc")
+      ? parseRc(content)
+      : JSON.parse(content);
+    if (!isPlainObject(value)) throw new TypeError("Config must be an object.");
+    return value;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const line of content.split(/\\r?\
/)) {
+    const trimmed = line.trim();
+    if (!trimmed || trimmed.startsWith("#")) continue;
+    const equals = trimmed.indexOf("=");
+    if (equals === -1) throw new TypeError("Expected key=value.");
+    const key = trimmed.slice(0, equals).trim();
+    let value = trimmed.slice(equals + 1).trim();
+    if (!key) throw new TypeError("Missing key.");
+    if (value.startsWith('"') && value.endsWith('"') && value.length >= 2) {
+      value = value.slice(1, -1);
+    }
+    values[key] = value === "true" ? true : value === "false" ? false
+      : value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)
+      ? Number(value)
+      : value;
+  }
+  return values;
+}
+
+export function flattenConfig(
+  values: Record<string, unknown>,
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  const flatten = (value: unknown, key: string) => {
+    if (isPlainObject(value)) {
+      for (const [childKey, childValue] of Object.entries(value)) {
+        flatten(childValue, key ? `${key}.${childKey}` : childKey);
+      }
+    } else {
+      result[toCamelCase(key)] = value;
+    }
+  };
+  for (const [key, value] of Object.entries(values)) flatten(value, key);
+  return result;
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return !!value && typeof value === "object" && !Array.isArray(value) &&
+    Object.getPrototypeOf(value) === Object.prototype;
+}
+
+function toCamelCase(key: string): string {
+  return key.replace(/-([a-zA-Z0-9])/g, (_, char: string) => char.toUpperCase());
+}
