import { ConfigParseError } from "./errors.ts";
import type { ConfigOptions } from "./types.ts";

export interface LoadedConfig {
  path?: string;
  values: Record<string, unknown>;
}

export async function loadConfig(
  options: ConfigOptions,
): Promise<LoadedConfig> {
  const paths = options.searchPaths ?? [Deno.cwd()];
  const formats = options.formats ?? [".json", ".rc"];
  let result: Record<string, unknown> = {};
  let configPath: string | undefined;

  for (const searchPath of paths) {
    const file = await findConfig(searchPath, options.name, formats);
    if (!file) continue;

    const content = await Deno.readTextFile(file);
    const values = parseConfig(content, file, options.parser);
    // Earlier paths take precedence when merging.
    result = options.mergeConfigs ? { ...values, ...result } : values;
    configPath ??= file;
    if (!options.mergeConfigs) break;
  }

  return { path: configPath, values: flattenConfig(result) };
}

async function findConfig(
  searchPath: string,
  name: string,
  formats: string[],
): Promise<string | undefined> {
  for (const format of formats) {
    const filename = format === ".rc" ? `.${name}rc` : `${name}${format}`;
    const path = `${searchPath.replace(/[\\/]$/, "")}/${filename}`;
    try {
      if ((await Deno.stat(path)).isFile) return path;
    } catch (error) {
      if (!(error instanceof Deno.errors.NotFound)) throw error;
    }
  }
}

function parseConfig(
  content: string,
  path: string,
  parser?: (content: string) => Record<string, unknown>,
): Record<string, unknown> {
  try {
    const value = parser
